<template>
    <div class="ClientBillListing" v-if="isInvoice">
        <loader :is-visible="isLoading"></loader>
        <tg-list :IsShowAction="true" :showCheckBox="true" ModuleName="Billing" :listType="['List']" :widgets="widgets"
            :RenderRowActionMethod="renderActions" SubModuleCode="Billing" IdentityColumn="BILL_ID"
            :ListData="CilentBillListing" :HeaderData="Headers" :callbackfunction="FetchData"
            :SearchFields="SearchSchema" :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :PageSize="pageSize"
            :ListDataCallBackFunction="FetchData" :LegendArray="LegendArray" :SortExp="sortExp" :SortBy="sortBy"
            :NorecordfoundText="$t('NoRecordfound')" v-on:LeftsearchButtonClick="leftCommonSearch"
            v-on:PagerButtonClick="pagerMethod" :isShowHeaderText="true" v-on:ActionButtonClick="actionButtonClick"
            :HeaderText="$t('Bills')" v-on:HeaderButtonClick="commonHeaderButtonClick"
            v-on:SortdataButtonClick="sortdata">

            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'STATUS'">
                    <span :title="data.row.STATUS_NAME" :class="getStatusClass(data.row)">
                        {{ getStatusLabel(data.row) }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'BILL_NUMBER'">
                    <div
                        v-if="data.row.STATUS_NAME != 'Paid' && data.row.STATUS_NAME != 'Bad Debt' && data.row.STATUS_NAME != 'Partial Paid' && data.row.STATUS_NAME != 'Cancelled' && data.row.STATUS_NAME != 'Cancel'">
                        <a href="javascript:;" data-toggle="tooltip" @click="handleEdit(data.row)">{{
                            data.row.BILL_NUMBER }}</a>
                    </div>
                    <div v-else>
                        {{ data.row.BILL_NUMBER }}
                    </div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'Company'">
                    <span>{{ data.row.COMPANY_NAME }}</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'BILL_NET_TOTAL'">
                    <a href="javascript:;" @click="openPaymentHistory(data.row)"><i aria-hidden="true"></i>
                        {{ $n(data.row.BILL_NET_TOTAL, "currency", $getLocaleByCurrency(getCurrencyForRow(data.row))) }}
                    </a>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'CONVERT_AMOUNT'">
                    <span>
                        {{ $n(data.row.CONVERT_AMOUNT, "currency", $getLocaleByCurrency(getCurrencyForRow(data.row))) }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'BILL_ISSUE_DATE'">
                    <span>
                        {{ $options.filters.formatDate(data.row.CREATED_AT) }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'BILL_DUE_DATE'">
                    <span>
                        {{ $options.filters.formatDate(data.row.BILL_DUE_DATE) }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'BILLING_PERIOD'">
                    <span>
                        {{ getInvoiceBillingPeriod(data.row) }}
                    </span>
                </template>

                <template v-if="data.column.COLUMN_NAME == 'Outstanding'">
                    <span>
                        {{ $n(data.row.BILL_NET_TOTAL, "currency", $getLocaleByCurrency(getCurrencyForRow(data.row))) }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'CONVERT_OUTSTANDING_AMOUNT'">
                    <span>
                        {{ $n(data.row.CONVERT_OUTSTANDING_AMOUNT, "currency",
                            $getLocaleByCurrency(getCurrencyForRow(data.row))) }}
                    </span>
                </template>

                <!-- <template v-if="data.column.COLUMN_NAME == 'PARENT_INVOICE'">
                    <span>
                        <a href="javascript:;" title="" class="note_0 text-dark enable viewdivisionnotes float-right"
                            data-original-title="View" data-toggle-tooltip="tooltip">
                            <i class="fa fa-file-text-o" style="font-size:20px;" aria-hidden="true"></i>
                            <span class="noti-circle noti-orange">{{ data.row.PARENT_INVOICE ? data.row.PARENT_INVOICE :
                                0
                                }}</span>
                        </a>
                    </span>
                </template> -->
            </template>
        </tg-list>

        <Attachment v-if="isAttachment" :BillId="billId"></Attachment>
        <PaymentHistroy v-if="isPaymentHistory" :BillId="BillId"></PaymentHistroy>
        <PayNow v-if="isPayment" :PaymentData="PaymentData"></PayNow>
        <InvoiceHistory v-if="isInvoiceHistory" :BillId="BillId"></InvoiceHistory>
        <SendBill v-if="isSendBill" :BillId="BillId" :InvoiceBillId="InvoiceBillId"></SendBill>
        <InvoicePaySlip v-if="isPaySlip" :BillId="billId"></InvoicePaySlip>
        <InvoiceHistoryChange v-if="isInvoiceHistoryChange" :BillId="BillId"></InvoiceHistoryChange>
    </div>
    <div v-else>
        <InvoiceTemplate v-if="isTemplate" :details="templatedata" @backtoInvoiceList="backtoInvoiceList"
            :hitFrom="'MainInvoice'" />
    </div>
</template>
<script>
import DataService from '../../services/DataService';
import ClientBillListingSchema from './ClientBillListingSchema';
import Attachment from '../Client/ClientDetails/Attachment.vue'
import PaymentHistroy from './PaymentHistroy.vue';
import PayNow from './PayNow.vue'
import InvoiceTemplate from "../Client/ClientDetails/InvoiceTemplate.vue";
import InvoiceHistory from '../Client/ClientDetails/InvoiceHistory.vue';
import SendBill from '../Client/ClientDetails/SendBill.vue';
import InvoicePaySlip from '../Client/ClientDetails/InvoicePaySlip.vue';
import InvoiceHistoryChange from '../Client/ClientDetails/InvoiceHistoryChange.vue'

import moment from 'moment';


export default ({
    name: 'ClientBillListing',
    components: { Attachment, PaymentHistroy, PayNow, InvoiceTemplate, InvoiceHistory, SendBill, InvoicePaySlip, InvoiceHistoryChange },

    data() {
        return {
            isPaymentHistory: false,
            isAttachment: false,
            isPaged: 1,
            isCheckExtraFeatureUSICBILLING:false,
            isCheckExtraFeatureUtilityBilling:false,
            Headers: [
                {
                    COLUMN_NAME: "BILL_NUMBER",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Bill') + '#',
                    DISPLAY_ORDER: 1,
                    TITILE:"Edit Invoice",
                },
                {
                    COLUMN_NAME: "CLIENT_NAME",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Client'),
                    DISPLAY_ORDER: 2,
                },
                {
                    COLUMN_NAME: "Company",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Company'),
                    DISPLAY_ORDER: 3,
                },
                {
                    COLUMN_NAME: "PROJECT_NAME",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('project_id'),
                    DISPLAY_ORDER: 4,
                },
                {
                    COLUMN_NAME: "BILLING_PERIOD",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('BillingPeriod'),
                    DISPLAY_ORDER: 5,
                },
              {
                    COLUMN_NAME: "BILLING_DIVISION",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Division'),
                    DISPLAY_ORDER: 6,
                },
                {
                    COLUMN_NAME: "STATE",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('STATE'),
                    DISPLAY_ORDER: 7,
                },
                {
                    COLUMN_NAME: "BILL_ISSUE_DATE",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('IssueDate'),
                    DISPLAY_ORDER: 8,
                },
                {
                    COLUMN_NAME: "BILL_DUE_DATE",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('DueDate'),
                    DISPLAY_ORDER: 9,

                },
                {
                    COLUMN_NAME: "BILL_NET_TOTAL",
                    DATA_TYPE: "currency",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Amount'),
                    DISPLAY_ORDER: 10,
                },
                {
                    COLUMN_NAME: "STATUS",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('STATUS_NAME'),
                    DISPLAY_ORDER: 11,

                },

                {
                    COLUMN_NAME: "RECURRING_FREQUENCY",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Frequency'),
                    DISPLAY_ORDER: 12,
                },

                {
                    COLUMN_NAME: "CONVERT_AMOUNT",
                    DATA_TYPE: "currency",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: `${this.$t('Amount')} ${this.GetUserInfo.Currency}`,
                    DISPLAY_ORDER: 13,

                },
                {
                    COLUMN_NAME: "Outstanding",
                    DATA_TYPE: "currency",
                    SORTABLE: false,
                    VISIBLE: false,
                    DISPLAY_NAME: this.$t('InvoiceOutstanding'),
                    DISPLAY_ORDER: 14,

                },
                {
                    COLUMN_NAME: "CONVERT_OUTSTANDING_AMOUNT",
                    DATA_TYPE: "currency",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: `${this.$t('InvoiceOutstanding')} ${this.GetUserInfo.Currency}`,
                    DISPLAY_ORDER: 15,

                },
                {
                    COLUMN_NAME: "PARENT_INVOICE",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('ParentInvoice'),
                    DISPLAY_ORDER: 13,
                },


            ],

            listheaderbuttons: ClientBillListingSchema.buttons,
            SearchSchema: ClientBillListingSchema.SearchSchema,

            listActions:
                [
                    {
                        title: 'Edit',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-pencil text-info action-icon',
                        callbackfunction: 'handleEdit',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                    {
                        title: 'ViewBill',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-eye action-icon',
                        callbackfunction: 'handleViewBill',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                    {
                        title: 'ViewSummary',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-eye action-icon',
                        callbackfunction: 'SummaryInvoice',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                    {
                        title: 'ViewInvoiceBackup',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-eye action-icon',
                        callbackfunction: 'InvoiceBackup',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                    {
                        title: 'SendBill',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-eye text-info action-icon',
                        callbackfunction: 'handleSendBill',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                    {
                        title: 'PaySlip',
                        callbackfunction: 'clkPaySlip',
                        icon: 'fa fa-print pr-2 action-icon',
                        additionalSpan: ''
                    },
                    {
                        title: 'Payment',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-usd text-info action-icon',
                        callbackfunction: 'handlePayment',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                    {
                        title: 'InvoiceHistory',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-history action-icon',
                        callbackfunction: 'handleInvoiceHistory',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                    {
                        title: 'ViewTalygenBackup',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-eye action-icon',
                        callbackfunction: 'TalygenBackup',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                    {
                        title: 'InvoiceHistoryChange',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-history text-info action-icon',
                        callbackfunction: 'handleInvoiceHistoryChange',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                    {
                        title: 'Attachment',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-upload text-primary action-icon',
                        callbackfunction: 'handleAttachment',
                        isDisabled: false,
                        additionalSpan: ''
                    },


                ],
            TotalRecords: 0,
            pageSize: 10,
            pageNum: 1,
            sortBy: '',
            searchCondition: '',
            GroupStart: 1,
            GroupEnd: 3,
            CurrentPage: 1,
            TotalPages: 0,
            sortExp: '',
            noRecords: false,
            LegendArray: [{
                class: 'legend-upcoming colorboxsquare',
                text: (this.$t('Bills')) + '(s) generated from milestone'
            },
            {
                class: 'legend-Progress colorboxsquare',
                text: (this.$t('Shared Company Invoice'))
            }
            ],
            CilentBillListing: [],
            widgets: [],
            inoviceStats: {},
            billId: '',
            isPayment: false,
            PaymentData: '',
            isInvoice: true,
            isTemplate: false,
            templatedata: {},
            isInvoiceHistory: false,
            isSendBill: false,
            isPaySlip: false,
            UserType: null,
            InvoiceBillId: '',
            isInvoiceHistoryChange: false,
            Currency: 'USD',
        }
    },
    async created() {
        var vm = this;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.Currency = this.GetUserInfo.Currency.replace(/[()]/g, '');
        await vm.CheckFeaturesForCompany('USICBILLING'),
        await vm.CheckFeaturesForCompany('UTILITY_BILLING')

        await vm.Widget();
        await vm.FetchData();
        await ClientBillListingSchema.bindleftCommonSearchdropdown(vm, 'Company', 'Client');
    },
    methods: {


                CheckFeaturesForCompany: async function (type) {
            var vm = this;
            var appendingUrl = `featureCode=${type}`;
            await DataService.CheckExtraFeatures(appendingUrl).then(function (response) {
                if(type == 'USICBILLING'){
                    if (response.data == true) {
                         vm.isCheckExtraFeatureUSICBILLING = true;
                    } else {
                         vm.isCheckExtraFeatureUSICBILLING = false;
                    }
                }
                else if(type == 'UTILITY_BILLING'){
                    if (response.data == true) {
                         vm.isCheckExtraFeatureUtilityBilling = true;
                    } else {
                         vm.isCheckExtraFeatureUtilityBilling = false;
                    }
                }
               
            });
        },
        async Widget() {
            var vm = this;
            vm.isLoading = true;
            let url = `projectId=&clientId=&invoiceNum=&isRecurring=0&amountTo=&amountFrom=&stringbillDueDateTo=&stringbillDueDateFrom=&stringbillIssueDateTo=&stringbillIssueDateFrom=&stringcreatedAtTo=&stringcreatedAtFrom=&statusId`;
            try {
                const response = await DataService.GetInvoiceStatistics(url);
                if (response && response.data) {
                    vm.inoviceStats = response.data.result;
                    vm.widgets = [];
                    let durationObj = {
                        icon: "fa fa-clock-o",
                        name: `Duration`,
                        class: "one_wid",
                        value: vm.inoviceStats.period != null ? vm.inoviceStats.period : ""
                    };
                    let dueObj = {
                        icon: "fa fa-dollar",
                        name: `Due ${vm.GetUserInfo.Currency}`,
                        class: "two_wid",
                        value: vm.inoviceStats.dueAmount != null ? vm.inoviceStats.dueAmount : "0.00"
                    };
                    let receivedObj = {
                        icon: "fa fa-dollar",
                        name: `Received ${vm.GetUserInfo.Currency}`,
                        class: "three_wid",
                        value: vm.inoviceStats.amountRecived != null ? vm.inoviceStats.amountRecived : "0.00"
                    };
                    vm.widgets.push(durationObj, dueObj, receivedObj);
                }
            } catch (error) {
                console.error("Error fetching invoice statistics:", error);
            } finally {
                vm.isLoading = false;
            }
        },
        parseQueryString(queryString) {
            const params = {};
            if (!queryString) return params;
            
            const pairs = queryString.split('&');
            pairs.forEach(pair => {
                const [key, value] = pair.split('=');
                if (key && value !== undefined) {
                    const decodedKey = decodeURIComponent(key);
                    const decodedValue = decodeURIComponent(value);
                    
                    if (params[decodedKey]) {
                        if (Array.isArray(params[decodedKey])) {
                            params[decodedKey].push(decodedValue);
                        } else {
                            params[decodedKey] = [params[decodedKey], decodedValue];
                        }
                    } else {
                        params[decodedKey] = decodedValue;
                    }
                }
            });
            return params;
        },
        processDateRangeParams(searchParams) {
            const processedParams = {};
            
            Object.keys(searchParams).forEach(key => {
                const value = searchParams[key];
                
                // Handle date range parameters that come in "from|to" format
                if (typeof value === 'string' && value.includes('|')) {
                    const [fromValue, toValue] = value.split('|');
                    
                    // Map date range parameters
                    if (key === 'stringbillIssueDateFrom') {
                        processedParams.stringbillIssueDateFrom = fromValue || '';
                        processedParams.stringbillIssueDateTo = toValue || '';
                    } else if (key === 'timePeriodFrom') {
                        processedParams.timePeriodFrom = fromValue || '';
                        processedParams.timePeriodTo = toValue || '';
                    } else if (key === 'stringbillDueDateFrom') {
                        processedParams.stringbillDueDateFrom = fromValue || '';
                        processedParams.stringbillDueDateTo = toValue || '';
                    } else {
                        // For other parameters, keep as is
                        processedParams[key] = value;
                    }
                } else {
                    processedParams[key] = value;
                }
            });
            
            return processedParams;
        },
        buildQueryStringFromParams(params) {
            const queryParts = [];
            Object.keys(params).forEach(key => {
                if (params[key] !== null && params[key] !== undefined && params[key] !== '') {
                    queryParts.push(`${encodeURIComponent(key)}=${encodeURIComponent(params[key])}`);
                }
            });
            return queryParts.join('&');
        },
        buildRequestObject() {
            const baseParams = {
                sortBy: this.sortBy || '',
                sortExp: this.sortExp || '',
                pageSize: this.pageSize || 10,
                pageNum: this.pageNum || 1,
                billId: 0,
                isPaged: this.isPaged || '1'
            };
            
            if (this.searchCondition) {
                const searchParams = this.parseQueryString(this.searchCondition);
                const processedParams = this.processDateRangeParams(searchParams);
                
                const mappedParams = {};
                Object.keys(processedParams).forEach(key => {
                    let mappedKey = key;
                    if (key === 'bill_id') {
                        mappedKey = 'billId';
                    }
                    mappedParams[mappedKey] = processedParams[key];
                });
                
                return { ...baseParams, ...mappedParams };
            }
            
            return baseParams;
        },
        async FetchData() {
            
            var vueObj = this;
            vueObj.CilentBillListing = [];
            
            const requestObject = vueObj.buildRequestObject();
            
            // Build GET query string with processed date ranges
            let queryString = `sortBy=${vueObj.sortBy}&sortExp=${vueObj.sortExp}&pageSize=${vueObj.pageSize}&pageNum=${vueObj.pageNum}&bill_id=0&isPaged=${vueObj.isPaged}`;
            if (this.searchCondition) {
                const searchParams = vueObj.parseQueryString(this.searchCondition);
                const processedParams = vueObj.processDateRangeParams(searchParams);
                const searchQueryString = vueObj.buildQueryStringFromParams(processedParams);
                if (searchQueryString) {
                    queryString += `&${searchQueryString}`;
                }
            }
            
            const usePost = this.searchCondition && this.searchCondition.length > 0;
            
            try {
                vueObj.isLoading = true;
                const response = usePost 
                    ? await DataService.GetClientBillListingPost(requestObject)
                    : await DataService.GetClientBillListing(queryString);
                if (response.data && response.data.result) {
                    vueObj.Headers.forEach((column) => {
                        column.settings = null;
                        if (column.COLUMN_NAME == 'STATUS'
                            || column.COLUMN_NAME == 'BILL_NUMBER'
                            || column.COLUMN_NAME == 'BILL_NET_TOTAL'
                            || column.COLUMN_NAME == 'BILL_ISSUE_DATE'
                            || column.COLUMN_NAME == 'BILL_DUE_DATE'
                            || column.COLUMN_NAME == 'BILLING_PERIOD'
                            || column.COLUMN_NAME == 'BILL_NET_TOTAL'
                            || column.COLUMN_NAME == 'Outstanding'
                            || column.COLUMN_NAME == 'CONVERT_AMOUNT'
                            || column.COLUMN_NAME == 'CONVERT_OUTSTANDING_AMOUNT'
                            // || column.COLUMN_NAME == 'PARENT_INVOICE'
                            || column.COLUMN_NAME == 'Company') {
                            column.settings = {
                                isInSlot: true
                            };
                        }
                        // Hide specific columns when USICBILLING feature is enabled
                        if (column.COLUMN_NAME == 'Company' ||
                            column.COLUMN_NAME == 'PROJECT_NAME' ||
                            column.COLUMN_NAME == 'PARENT_INVOICE' ||
                            column.COLUMN_NAME == 'RECURRING_FREQUENCY' ||
                             column.COLUMN_NAME == 'BILL_DUE_DATE' ||
                            column.COLUMN_NAME == 'Outstanding' ||
                            column.COLUMN_NAME == 'CONVERT_AMOUNT' ||
                            column.COLUMN_NAME == 'CONVERT_OUTSTANDING_AMOUNT') {
                            column.VISIBLE = !vueObj.isCheckExtraFeatureUSICBILLING;
                        }
                    });



                    const parsedData = JSON.parse(response.data.result); // Parse once

                    if (parsedData.data && parsedData.data.length > 0) {
                        vueObj.CilentBillListing = parsedData.data;
                        const totalRecords = parsedData.data[0].TOTAL_RECORDS;
                        vueObj.TotalRecords = totalRecords ? parseInt(totalRecords) || 0 : 0;
                        vueObj.TotalPages = vueObj.TotalRecords > 0 ? Math.ceil(vueObj.TotalRecords / vueObj.pageSize) : 0;
                        vueObj.CurrentPage = vueObj.pageNum || 1;
                        vueObj.noRecord = false;
                    }
                    else {
                        vueObj.noRecord = true;
                        vueObj.TotalRecords = 0;
                        vueObj.TotalPages = 0;
                        vueObj.CurrentPage = 1;
                        vueObj.CilentBillListing = [];
                        vueObj.isLoading = false;

                    }

                }
                else {
                    vueObj.noRecord = true;
                    vueObj.TotalRecords = 0;
                    vueObj.TotalPages = 0;
                    vueObj.CurrentPage = 1;
                    vueObj.CilentBillListing = [];
                }

            } catch (error) {
                console.error('Error fetching client bill listing:', error);
                vueObj.noRecord = true;
                vueObj.TotalRecords = 0;
                vueObj.TotalPages = 0;
                vueObj.CurrentPage = 1;
                vueObj.CilentBillListing = [];
            } finally {
                vueObj.isLoading = false;

                console.log('Fetch operation complete');
            }
        },
        OpenPlanDetail() {
            
        },
        commonHeaderButtonClick(event) {
            switch (event.callbackfunction) {
                case "mannualBill":
                    this.mannualBill(0);
                    break;
                case "download":
                    this.DownloadBillList();
                    break;
                case "markAsSent":
                    this.MarkStatus('CLBSND');
                    break;
                case "markAsPaid":
                    this.MarkStatus('CLBPAD');
                    break;
                case "markAsDisputed":
                    this.MarkStatus('CLBDSPT');
                    break;
                case "markAsBadDebt":
                    this.MarkStatus('CLBBDBT');
                    break;
                case "markAsCancelled":
                    this.MarkStatus('CLBCNCL');
                    break;
                case "BackToList":
                    this.BackToList();
                    break;
            }
        },

        renderActions(row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'Edit':
                        action.isVisible = true;
                        action.isDisabled = row.STATUS_CODE == "CLBPAD" || row.STATUS_CODE == "CLBPPAD" ? true : false;
                        break
                    case 'ViewBill':
                        action.isVisible = (self.isCheckExtraFeatureUtilityBilling == true ? true : false);
                        break
                    case 'SendBill':
                        action.isVisible = (self.isCheckExtraFeatureUtilityBilling == true ? true : false);
                        break
                    case 'ViewSummary':
                        action.isVisible = self.isCheckExtraFeatureUSICBILLING;
                        break   
                    case'ViewInvoiceBackup': 
                         action.isVisible = self.isCheckExtraFeatureUSICBILLING;;
                        break         
                    case "PaySlip":
                        action.isVisible = true;
                        action.isDisabled = row.STATUS_CODE == "CLBPAD" || row.STATUS_CODE == "CLBPPAD" ? false : true;
                        break;
                    case 'Payment':
                        action.isVisible = self.UserType == 'CL' ? false : true;
                        action.isDisabled = row.STATUS_CODE == "CLBPAD" || row.STATUS_CODE == "CLBSND" || row.STATUS_CODE == "CLBPPAD" ? false : true;
                        break
                    case 'ViewTalygenBackup':
                        action.isVisible = self.isCheckExtraFeatureUSICBILLING;;
                        break    
                    case 'InvoiceHistory':
                        action.isVisible = true;
                        break
                    case 'InvoiceHistoryChange':
                        action.isVisible = true;
                        break
                    case 'Attachment':
                        action.isVisible = true;
                        break


                }
