        async DownloadBillList() {
            
            var vm = this;
            const requestObject = vm.buildRequestObject();
            
            // Build GET query string with processed date ranges
            let queryString = `sortBy=${vm.sortBy}&sortExp=${vm.sortExp}&pageSize=${vm.pageSize}&pageNum=${vm.pageNum}&bill_id=0&isPaged=${vm.isPaged}`;
            if (this.searchCondition) {
                const searchParams = vm.parseQueryString(this.searchCondition);
                const processedParams = vm.processDateRangeParams(searchParams);
                const searchQueryString = vm.buildQueryStringFromParams(processedParams);
                if (searchQueryString) {
                    queryString += `&${searchQueryString}`;
                }
            }
            
            const usePost = this.searchCondition && this.searchCondition.length > 0;
            const response = usePost 
                ? await DataService.GetClientBillListingPost(requestObject)
                : await DataService.GetClientBillListing(queryString);

            
            if (response.data != "" && response.data != null) {
                let data = JSON.parse(response.data.result);
                if (data.data.length > 0) {
                    vm.ConvertJSONToCSV(data.data, "Invoice", true);
                }
            }

        },
        ConvertJSONToCSV: function (data, filename, showHeader) {
            const excludeColumns = [
                "BILL_ID",
                "BILL_RECORD_AMOUNT",
                "COMPANY_ID",
                "COMPANY_NAME",
                "IS_AUTO_SEND",
                "ISO_CODE",
                "IS_RECURRING",
                "MILESTONE_ID",
                "RECURRING_FREQUENCY",
                "RECURRING_STATUS",
                "ROWNUMBER",
                "STATUS_CODE",
                "TEMPLATE_ID",
                "TIME_ROUNDING",
                "TOTAL_RECORDS",
            ];
            const headerMap = {
                BILL_NUMBER: "Invoice No",
                CLIENT_NAME: "Contract",
                PROJECT_NAME: "Project Name",
                PARENT_INVOICE: "Parent Invoice",
                CREATED_AT: "Issue Date",
                BILL_DUE_DATE: "Due Date",
                PAYMENT_CREATED_AT: "Payment Date",
                BILL_NET_TOTAL: "Amount",
                STATUS_NAME: " Status",
            };
            if (data && Array.isArray(data) && data.length > 0) {
                const headers = Object.keys(data[0]);
                const filteredHeaders = headers.filter(
                    (header) => !excludeColumns.includes(header)
                );
                const mappedHeaders = filteredHeaders.map(
                    (header) => headerMap[header] || header
                );
                const rows = data.map((row) => {
                    return mappedHeaders
                        .map((mappedHeader) => {
                            const originalHeader =
                                filteredHeaders[mappedHeaders.indexOf(mappedHeader)];
                            let cellValue =
                                row[originalHeader] !== undefined &&
                                    row[originalHeader] !== null
                                    ? String(row[originalHeader])
                                    : "";
                            if (
                                cellValue.includes(",") ||
                                cellValue.includes("\n") ||
                                cellValue.includes('"')
                            ) {
                                cellValue = `"${cellValue.replace(/"/g, '""')}"`;
                            }
                            return cellValue;
                        })
                        .join(",");
                });
                const csvContent = (showHeader ? [mappedHeaders.join(",")] : [])
                    .concat(rows)
                    .join("\n");
                const blob = new Blob([csvContent], {
                    type: "text/csv;charset=utf-8;",
                });
                const link = document.createElement("a");
                link.setAttribute("href", URL.createObjectURL(blob));
                link.setAttribute("download", `${filename}.csv`);
                link.click();
            } else {
                console.log("No valid data to convert.");
            }
        },
        MarkStatus(status) {
            


            var vm = this;

            var selectedBillIds = [];
            var selectedParicalPaidOrPaid = [];
            var selectedInvoiceNumber = [];

            vm.CilentBillListing.forEach((item) => {
                var ISDisabled = false;

                if (item.isSelected == true) {
                    selectedBillIds.push(item.BILL_ID);
                    if (item.STATUS_CODE == "CLBPAD" || item.STATUS_CODE == "CLBPPAD" || item.STATUS_CODE == "CLBCNCL") {
                        selectedParicalPaidOrPaid.push(item.BILL_ID);
                        selectedInvoiceNumber.push(item.BILL_NUMBER);
                    }

                }
            });
            if (selectedParicalPaidOrPaid.length > 0) {
                const invoiceLabel = selectedInvoiceNumber.length > 1 ? "invoices are" : "invoice is";
                const unselectLabel = selectedInvoiceNumber.length > 1 ? "these invoices" : "this invoice";
                vm.ShowAlert(`${selectedInvoiceNumber.join(", ")} - ${invoiceLabel} already paid. Please unselect ${unselectLabel} before proceeding.`, "failure");
                // Prevent any future action
                return;
            }
            if (selectedBillIds.length === 0) {
                vm.ShowAlert("Please select at least one invoice.", "failure");
                return;
            }
            var billIds = selectedBillIds.join(",");
            vm.UpdateStatus(billIds, status)
        },
        UpdateStatus(val, status) {
            
            var vm = this
            var resourcestatus = "";
            var msg = "";
            if (status == 'CLBSND') {
                resourcestatus = "MarkSent";
            }
            else if (status == 'CLBPAD') {
                resourcestatus = "MarkPaid";
            }
            else if (status == 'CLBDSPT') {
                resourcestatus = "MarkDisputed";
            }
            else if (status == 'CLBBDBT') {
                resourcestatus = "MarkBadDebt";
            }
            else if (status == 'CLBCNCL') {
                resourcestatus = "MarkCancel";
            }
            if (status == 'CANPWORKDAY') {
                msg = vm.$t("ConfirmCancelWorkday")
            }
            else if (status == 'CLBSND') {
                msg = vm.$t("ConfirmMesageExporttoWorkday")
            }
            else if (status == 'CLBCNCL') {
                msg = vm.$t("MarkCancel")
            }
            else {
                msg = vm.$t("InvoiceConfirm").replace("?", " ") + " " + vm.$t(resourcestatus) + "?"

            }
            vm.confirmR(msg, true, false, function (result) {
                if (result === undefined) {
                    var url = `billIds=${val}&statusCode=${status}`;
                    DataService.UpdateClientInvoiceStatus(url).then(
                        (response) => {
                            //debugger;
                            if (response.data[0].ERROR_CODE == 1) {
                                vm.ShowAlert(vm.$t("RecordUpdatedSuccessfully"), "success");
                                vm.FetchData();
                            } else {
                                vm.ShowAlert(
                                    vm.$t("ErrorWhileProcessingRequest"),
                                    "failure"
                                );
                            }
                        }
                    );
                }
            })
        },
