async function bindleftCommonSearchdropdown(ths, modulename, filtername) {
    var vm = ths;
    let param = `reqForm=leftSearch`;

    try {
        const response = await DataService.GetleftSearchDropdownData(param);
        if (response.data != null) {
            // Parse JSON responses once and handle potential errors
            let parsedData = {};
            try {
                parsedData.clientList = response.data.clientList ? JSON.parse(response.data.clientList).data : [];
            } catch (e) {
                console.error('Error parsing clientList:', e);
                parsedData.clientList = [];
            }
            
            try {
                parsedData.projectList = response.data.projectList ? JSON.parse(response.data.projectList).data : [];
            } catch (e) {
                console.error('Error parsing projectList:', e);
                parsedData.projectList = [];
            }
            
            try {
                parsedData.state = response.data.state ? JSON.parse(response.data.state).data : [];
            } catch (e) {
                console.error('Error parsing state:', e);
                parsedData.state = [];
            }
            
            try {
                parsedData.statusType = response.data.statusType ? JSON.parse(response.data.statusType).data : [];
            } catch (e) {
                console.error('Error parsing statusType:', e);
                parsedData.statusType = [];
            }
            
            try {
                parsedData.invoiceDurationList = response.data.invoiceDurationList ? JSON.parse(response.data.invoiceDurationList) : [];
            } catch (e) {
                console.error('Error parsing invoiceDurationList:', e);
                parsedData.invoiceDurationList = [];
            }

            // Helper function to find field by name
            const findFieldByName = (fieldName) => {
                return vm.SearchSchema.find(field => field.fieldName === fieldName);
            };

            // Process client list with filter and map for better performance
            if (parsedData.clientList && parsedData.clientList.length > 0) {
                const clientField = findFieldByName('Client');
                if (clientField) {
                    clientField.listOptions = parsedData.clientList
                        .filter(item => item.Name && item.Id && typeof item.Id === 'string' && item.Id.trim() !== '')
                        .map(item => {
                            try {
                                const idValue = item.Id.split('^')[0];
                                return {
                                    name: item.Name,
                                    value: idValue
                                };
                            } catch (error) {
                                console.error('Error splitting item.Id for', item, error);
                                return null;
                            }
                        })
                        .filter(item => item !== null);
                }
            }

            // Process status type - ensure values are strings for proper checkbox comparison
            if (parsedData.statusType && parsedData.statusType.length > 0) {
                const statusField = findFieldByName('InvoiceStatus');
                if (statusField) {
                    statusField.listOptions = parsedData.statusType
                        .filter(item => item.STATUS_NAME && item.status_id != null)
                        .map(item => ({
                            name: item.STATUS_NAME,
                            value: item.status_id
                        }));
                }
            }

            // Process project list
            if (parsedData.projectList && parsedData.projectList.length > 0) {
                const projectField = findFieldByName('Project');
                if (projectField) {
                    projectField.listOptions = parsedData.projectList.map(item => ({
                        name: item.Name,
                        value: item.Id
                    }));
                }
            }

            // Process state list
            if (parsedData.state && parsedData.state.length > 0) {
                const stateField = findFieldByName('STATE');
                if (stateField) {
                    stateField.listOptions = parsedData.state.map(item => ({
                        name: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                        value: item.STATE_ID
                    }));
                }
            }

            // Process invoice duration list
            if (parsedData.invoiceDurationList && parsedData.invoiceDurationList.length > 0) {
                const frequencyField = findFieldByName('Frequency');
                if (frequencyField) {
                    frequencyField.listOptions = parsedData.invoiceDurationList.map(item => ({
                        name: item.Name,
                        value: item.Value
                    }));
                }
            }
        }
    } catch (error) {
        console.error('Error fetching dropdown data:', error);
    }
}


export default { buttons, SearchSchema, bindleftCommonSearchdropdown };